#include<stdio.h>
int main()
{
    long long n,a,b,c,i,j,k,diff,min=10000000000,max;
    scanf("%lld",&n);
    for(i=1;i*i*i<=n;i++)
    {
        if(n%i==0)
        {
            for(j=i;j*j<=n/i;j++)
            {
                if(n%j==0)
                k=n/(i*j);
                a=i+1;b=j+2;c=k+2;
                if((a-1)*(b-2)*(c-2)==n)
                diff=(a*b*c)-n;
                if(min>diff)
                min=diff;

        }
        }
    }
    max=9*(n+1)-n;
    printf("%lld %lld",min,max);
    return 0;
}

