struct Scanner<'a> {
    cin: StdinLock<'a>,
}

impl<'a> Scanner<'a> {
    #[allow(dead_code)]
    fn new(cin: StdinLock<'a>) -> Scanner<'a> {
        Scanner {cin: cin}
    }

    #[allow(dead_code)]
    fn read1<T: FromStr>(&mut self) -> Option<T> {
        let token = self.cin.by_ref().bytes().map(|c| c.unwrap() as char)
                    .skip_while(|c| c.is_whitespace())
                    .take_while(|c| !c.is_whitespace())
                    .collect::<String>();
        token.parse::<T>().ok()
    }

    #[allow(dead_code)]
    fn read<T: FromStr>(&mut self) -> T {
        self.read1().unwrap()
    }
}

fn main() {
    let cin = stdin();
    let cin = cin.lock();
    let mut sc = Scanner::new(cin);

    let n: i64 = sc.read();
    let max_r = 9 * (n + 1) - n;
    let mut min_r: i64 = i64::max_value();
    for a in 2..n+2 {
        if (a - 1) * (a - 1) > n {
            break;
        }
        if n % (a - 1) != 0 {
            continue;
        }
        let m = n / (a - 1);
        for b in 3..m+3 {
            if (b - 2) * (b - 2) > m {
                break;
            }
            if m % (b - 2) == 0 {
                let c = m / (b - 2) + 2;
                min_r = min(min_r, a * b * c - n);
            }
        }
    }

    println!("{} {}", min_r, max_r);
}
